class CommentStars{constructor(t,s){this.starsWrap=t,this.options=s,this.stars=this.starsWrap.querySelectorAll("svg"),this.setStars()}setStars(){let s=parseInt(this.starsWrap.getAttribute(this.options.attribute)),r=0;this.stars.forEach(t=>{r<s?t.classList.add(this.options.classActive):t.classList.add(this.options.classNotActive),r++})}}function newCommentStars(t,s){return new CommentStars(t,s)}export{newCommentStars};